import numpy as np

def hard_voting(predictions: list[np.ndarray]) -> np.ndarray:
    stacked = np.array(predictions)  # (K, N)
    N = stacked.shape[1]
    result = np.zeros(N, dtype=int)
    for i in range(N):
        votes = stacked[:, i].astype(int)
        result[i] = np.bincount(votes).argmax()
    return result

def soft_voting(probas: list[np.ndarray]) -> np.ndarray:
    avg_proba = np.mean(np.array(probas), axis=0)  # (N, C)
    return np.argmax(avg_proba, axis=1)
